"""Verify a self-signed TLS certificate."""

import sys
import subprocess
from datetime import datetime


def main():
    cert_path = "/app/ssl/server.crt"

    # Check that the certificate file exists
    try:
        with open(cert_path, "r") as f:
            cert_content = f.read()
    except FileNotFoundError:
        print(f"ERROR: Certificate file not found at {cert_path}")
        sys.exit(1)

    if "BEGIN CERTIFICATE" not in cert_content:
        print("ERROR: File does not appear to be a valid PEM certificate")
        sys.exit(1)

    # Use openssl to parse and display certificate details
    try:
        result = subprocess.run(
            ["openssl", "x509", "-in", cert_path, "-noout", "-subject", "-enddate"],
            capture_output=True, text=True, check=True
        )
        output = result.stdout.strip()
        print(output)

        # Extract Common Name from subject line
        for line in output.splitlines():
            if "subject=" in line:
                cn_part = line.split("CN = ")[-1] if "CN = " in line else ""
                if not cn_part and "CN=" in line:
                    cn_part = line.split("CN=")[-1]
                print(f"Common Name: {cn_part}")

        # Extract expiration date and format it
        for line in output.splitlines():
            if "notAfter=" in line:
                raw_date = line.split("=", 1)[1].strip()
                # Parse OpenSSL date format: "Apr 24 07:28:17 2027 GMT"
                try:
                    exp_date = datetime.strptime(raw_date, "%b %d %H:%M:%S %Y %Z")
                except ValueError:
                    exp_date = datetime.strptime(raw_date, "%b  %d %H:%M:%S %Y %Z")
                print(f"Expiration Date: {exp_date.strftime('%Y-%m-%d')}")

    except subprocess.CalledProcessError as e:
        print(f"ERROR: Failed to parse certificate: {e.stderr}")
        sys.exit(1)

    print("Certificate verification successful")


if __name__ == "__main__":
    main()
